const numbers = $input.first().json;
const total = numbers.length;
const green = numbers.filter(n => n.qualityRating === 'GREEN').length;
const yellow = numbers.filter(n => n.qualityRating === 'YELLOW').length;
const red = numbers.filter(n => n.qualityRating === 'RED').length;
const disconnected = numbers.filter(n => n.status === 'disconnected').length;
const banned = numbers.filter(n => n.status === 'banned').length;
const active = numbers.filter(n => n.status === 'active').length;
const paused = numbers.filter(n => n.status === 'paused').length;

const byProduct = {};
for (const n of numbers) {
  const key = n.productName ?? n.productSlug ?? 'Sin producto';
  if (!byProduct[key]) byProduct[key] = { active: 0, paused: 0, disconnected: 0 };
  byProduct[key][n.status] = (byProduct[key][n.status] ?? 0) + 1;
}

const productLines = Object.entries(byProduct)
  .map(([k, v]) => `  • ${k}: ${v.active} activos, ${v.paused} pausados, ${v.disconnected} caídos`)
  .join('\n');

return [{
  json: {
    total, green, yellow, red, disconnected, banned, active, paused, productLines,
    hasIssues: red > 0 || disconnected > 0 || banned > 0
  }
}];

